945:         public Timer(long timestamp, K key, W window) {
946:             this.timestamp = timestamp;
947:             this.key = key;
948:             this.window = window;
949:         }
950: 
951:         @Override
952:         public int compareTo(Timer<K, W> o) {
953:             return Long.compare(this.timestamp, o.timestamp);
954:         }
955: 
956:         @Override
957:         public boolean equals(Object o) {
958:             if (this == o) {
959:                 return true;
960:             }
961:             if (o == null || getClass() != o.getClass()) {
962:                 return false;
963:             }
964: 
965:             Timer<?, ?> timer = (Timer<?, ?>) o;
966: 
967:             return timestamp == timer.timestamp
968:                     && key.equals(timer.key)
969:                     && window.equals(timer.window);
970:         }
971: 
972:         @Override
973:         public int hashCode() {
974:             int result = (int) (timestamp ^ (timestamp >>> 32));
975:             result = 31 * result + key.hashCode();
976:             result = 31 * result + window.hashCode();
977:             return result;
978:         }
