                                    (Tuple2<String, Integer>) invocation.getArguments()[0];
                            switch (element.f0) {
                                case "key1":
                                    return 3000L;
                                case "key2":
                                    switch (element.f1) {
                                        case 10:
                                            return 1000L;
                                        default:
                                            return 2000L;
                                    }
                                default:
                                    return 0L;
                            }
                        });

        ListStateDescriptor<Tuple2<String, Integer>> stateDesc =
                new ListStateDescriptor<>(
                        "window-contents",
                        STRING_INT_TUPLE.createSerializer(new SerializerConfigImpl()));

