    @Override
    public void processElement(StreamRecord<IN> element) throws Exception {
        final Collection<W> elementWindows =
                windowAssigner.assignWindows(
                        element.getValue(), element.getTimestamp(), windowAssignerContext);

        // if element is handled by none of assigned elementWindows
        boolean isSkippedElement = true;

        final K key = this.<K>getKeyedStateBackend().getCurrentKey();

        // Check if the element is late early, before processing for windows
        // For merging windows, this is important to prevent late elements from being
        // merged into windows that haven't expired yet
        boolean elementIsLate = isElementLate(element);

        if (windowAssigner instanceof MergingWindowAssigner) {
            MergingWindowSet<W> mergingWindows = getMergingWindowSet();

            if (!elementIsLate) {
                for (W window : elementWindows) {

                    // adding the new window might result in a merge, in that case the actualWindow
                    // is the merged window and we work with that. If we don't merge then
                    // actualWindow == window
                    W actualWindow =
                            mergingWindows.addWindow(
                                    window,
                                    new MergingWindowSet.MergeFunction<W>() {
                                        @Override
                                        public void merge(
                                                W mergeResult,
                                                Collection<W> mergedWindows,
                                                W stateWindowResult,
                                                Collection<W> mergedStateWindows)
                                                throws Exception {

                                            if ((windowAssigner.isEventTime()
                                                    && mergeResult.maxTimestamp() + allowedLateness
                                                            <= internalTimerService
                                                                    .currentWatermark())) {
                                                throw new UnsupportedOperationException(
                                                        "The end timestamp of an "
                                                                + "event-time window cannot become earlier than the current watermark "
                                                                + "by merging. Current watermark: "
                                                                + internalTimerService
                                                                        .currentWatermark()
                                                                + " window: "
                                                                + mergeResult);
                                            } else if (!windowAssigner.isEventTime()) {
                                                long currentProcessingTime =
                                                        internalTimerService
                                                                .currentProcessingTime();
                                                if (mergeResult.maxTimestamp()
                                                        <= currentProcessingTime) {
                                                    throw new UnsupportedOperationException(
                                                            "The end timestamp of a "
                                                                    + "processing-time window cannot become earlier than the current processing time "
                                                                    + "by merging. Current processing time: "
                                                                    + currentProcessingTime
                                                                    + " window: "
                                                                    + mergeResult);
                                                }
                                            }

                                            triggerContext.key = key;
                                            triggerContext.window = mergeResult;

                                            triggerContext.onMerge(mergedWindows);

                                            for (W m : mergedWindows) {
                                                triggerContext.window = m;
                                                triggerContext.clear();
                                                deleteCleanupTimer(m);
                                            }

                                            // merge the merged state windows into the newly
                                            // resulting
                                            // state window
                                            windowMergingState.mergeNamespaces(
                                                    stateWindowResult, mergedStateWindows);
                                        }
                                    });

                    // drop if the window is already late
                    if (isWindowLate(actualWindow)) {
                        mergingWindows.retireWindow(actualWindow);
                        continue;
                    }
                    isSkippedElement = false;

                    W stateWindow = mergingWindows.getStateWindow(actualWindow);
                    if (stateWindow == null) {
                        throw new IllegalStateException(
                                "Window " + window + " is not in in-flight window set.");
                    }

                    windowState.setCurrentNamespace(stateWindow);
                    windowState.add(element.getValue());

                    triggerContext.key = key;
                    triggerContext.window = actualWindow;

                    TriggerResult triggerResult = triggerContext.onElement(element);

                    if (triggerResult.isFire()) {
                        ACC contents = windowState.get();
                        if (contents != null) {
                            emitWindowContents(actualWindow, contents);
                        }
                    }

                    if (triggerResult.isPurge()) {
                        windowState.clear();
                    }
                    registerCleanupTimer(actualWindow);
                }
            }

            // need to make sure to update the merging state in state
            mergingWindows.persist();
        } else {
            // For non-merging windows, if element is late, skip processing
            if (!elementIsLate) {
                for (W window : elementWindows) {

                    // drop if the window is already late
                    if (isWindowLate(window)) {
                        continue;
                    }
                    isSkippedElement = false;

                windowState.setCurrentNamespace(window);
                windowState.add(element.getValue());

                triggerContext.key = key;
                triggerContext.window = window;

                TriggerResult triggerResult = triggerContext.onElement(element);

                if (triggerResult.isFire()) {
                    ACC contents = windowState.get();
                    if (contents != null) {
                        emitWindowContents(window, contents);
                    }
                }

                if (triggerResult.isPurge()) {
                    windowState.clear();
                }
                registerCleanupTimer(window);
            }
        }

        // side output input event if
        // element not handled by any window
        // late arriving tag has been set
        // windowAssigner is event time and current timestamp + allowed lateness no less than
        // element timestamp
        if (isSkippedElement && isElementLate(element)) {
            if (lateDataOutputTag != null) {
                sideOutput(element);
            } else {
                this.numLateRecordsDropped.inc();
            }
        }
    }

    @Override
    public void onEventTime(InternalTimer<K, W> timer) throws Exception {
        triggerContext.key = timer.getKey();
        triggerContext.window = timer.getNamespace();

        MergingWindowSet<W> mergingWindows;

        if (windowAssigner instanceof MergingWindowAssigner) {
            mergingWindows = getMergingWindowSet();
            W stateWindow = mergingWindows.getStateWindow(triggerContext.window);
            if (stateWindow == null) {
                // Timer firing for non-existent window, this can only happen if a
                // trigger did not clean up timers. We have already cleared the merging
                // window and therefore the Trigger state, however, so nothing to do.
                return;
            } else {
                windowState.setCurrentNamespace(stateWindow);
            }
        } else {
            windowState.setCurrentNamespace(triggerContext.window);
            mergingWindows = null;
        }

        TriggerResult triggerResult = triggerContext.onEventTime(timer.getTimestamp());

        if (triggerResult.isFire()) {
            ACC contents = windowState.get();
            if (contents != null) {
                emitWindowContents(triggerContext.window, contents);
            }
        }

        if (triggerResult.isPurge()) {
            windowState.clear();
        }

        if (windowAssigner.isEventTime()
                && isCleanupTime(triggerContext.window, timer.getTimestamp())) {
            clearAllState(triggerContext.window, windowState, mergingWindows);
        }

        if (mergingWindows != null) {
            // need to make sure to update the merging state in state
            mergingWindows.persist();
        }
    }

    @Override
    public void onProcessingTime(InternalTimer<K, W> timer) throws Exception {
        triggerContext.key = timer.getKey();
        triggerContext.window = timer.getNamespace();

        MergingWindowSet<W> mergingWindows;

        if (windowAssigner instanceof MergingWindowAssigner) {
            mergingWindows = getMergingWindowSet();
            W stateWindow = mergingWindows.getStateWindow(triggerContext.window);
            if (stateWindow == null) {
                // Timer firing for non-existent window, this can only happen if a
                // trigger did not clean up timers. We have already cleared the merging
                // window and therefore the Trigger state, however, so nothing to do.
                return;
            } else {
                windowState.setCurrentNamespace(stateWindow);
            }
        } else {
            windowState.setCurrentNamespace(triggerContext.window);
            mergingWindows = null;
        }

        TriggerResult triggerResult = triggerContext.onProcessingTime(timer.getTimestamp());

        if (triggerResult.isFire()) {
            ACC contents = windowState.get();
            if (contents != null) {
                emitWindowContents(triggerContext.window, contents);
            }
        }

        if (triggerResult.isPurge()) {
            windowState.clear();
        }

        if (!windowAssigner.isEventTime()
                && isCleanupTime(triggerContext.window, timer.getTimestamp())) {
            clearAllState(triggerContext.window, windowState, mergingWindows);
        }

        if (mergingWindows != null) {
            // need to make sure to update the merging state in state
            mergingWindows.persist();
        }
    }

    @Override
    public OperatorAttributes getOperatorAttributes() {
        boolean isOutputOnlyAfterEndOfStream =
